{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを正式に発足させる。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例会議を毎週水曜日10:00〜1時間枠で開催し、各部署から少なくとも1名の出席を必須とし、リモート参加を認める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "開発ベンダーとしてコマツバ・ソリューションズを選定し、技術面での協議と稟議起票を進める。",
      "decided_by": "郡司 明久/桐生 遥"
    },
    {
      "id": "D4",
      "content": "共通基盤の方式としてサクラ商事との共同利用を採用する。",
      "decided_by": "桐生 遥/沼田 賢一"
    },
    {
      "id": "D5",
      "content": "データ移行は第1フェーズでマスタ系データのみを行い、トランザクション系は旧システムを参照用に残して後続フェーズへ回す。",
      "decided_by": "芦田 巧/桐生 遥"
    },
    {
      "id": "D6",
      "content": "本番リリースの目標日付を2026年10月15日とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "移行方式として拠点をグループ分けして順次切り替える段階移行を採用する。",
      "decided_by": "桐生 遥/芦田 巧"
    },
    {
      "id": "D8",
      "content": "システム切り替えを土曜日の深夜帯から日曜日にまたがる時間帯で実施する。",
      "decided_by": "沼田 賢一/芦田 巧/東雲 美咲ら合意"
    },
    {
      "id": "D9",
      "content": "ユーザー権限定義は既存のロールを流用し、新規設計を行わない。",
      "decided_by": "芦田 巧/桐生 遥"
    },
    {
      "id": "D10",
      "content": "障害窓口を情報システム部ではなくQAチームとし、切り分け済みのケースのみが情シスへエスカレーションされる形とする。",
      "decided_by": "桐生 遥/白鳥 千夏提案"
    }
  ],
  "action_items": [
    {
      "id": "A1",
      "task": "在庫管理に関わる部署とその窓口名を記載した表形式での提出。",
      "assignee": "東雲 美咲",
      "due": "2026-05-19"
    },
    {
      "id": "A2",
      "task": "現行台数を倍増後、冗長構成などを間引いた構成での調達依頼書の作成・提出。",
      "assignee": "沼田 賢一",
      "due": "2026-05-15"
    },
    {
      "id": "A3",
      "task": "外部連携用APIのエンドポイント一覧と主要項目レイアウトを含むドラフト作成。",
      "assignee": "芦田 巧",
      "due": "2026-05-20"
    },
    {
      "id": "A4",
      "task": "コマツバ・ソリューションズとの契約に関する稟議書の作成・提出。",
      "assignee": "郡司 明久",
      "due": "2026-05-18"
    },
    {
      "id": "A5",
      "task": "開発ツールライセンスの単価確認（サブスクと年契約の両案で）。",
      "assignee": "郡司 明久",
      "due": "2026-06-01"
    },
    {
      "id": "A6",
      "task": "サクラ商事との共同利用に関する正式な回答書。技術条件部分は芦田 巧がレビュー。",
      "assignee": "桐生 遥",
      "due": "2026-05-16"
    },
    {
      "id": "A7",
      "task": "現行システムのテストケースを「残す」「捨てる」「修正必要」の3分類に整理。",
      "assignee": "白鳥 千夏",
      "due": "2026-05-29"
    },
    {
      "id": "A8",
      "task": "移行方式決定後の詳細ではなく、テスト観点と実施回数の枠組みを含めた計画書。",
      "assignee": "芦田 巧",
      "due": "2026-06-03"
    },
    {
      "id": "A9",
      "task": "ピーク想定シナリオを含む計画書を作成し、合格基準は「応答時間1.2秒以内（社内ネットワーク測定点）」を維持することとする。",
      "assignee": "白鳥 千夏",
      "due": "2026-06-03"
    },
    {
      "id": "A10",
      "task": "実際の切替作業の手順書。",
      "assignee": "沼田 賢一",
      "due": "2026-06-05"
    },
    {
      "id": "A11",
      "task": "各拠点の生産管理担当へのヒアリングおよび、複数回に分けた説明会の実施日程の枠組み案を提出。",
      "assignee": "東雲 美咲",
      "due": "2026-05-27"
    }
  ],
